$base='http://localhost:5000'; $count=300; $levels=@('debug','info','warn','error'); $entries=1..$count | % { [PSCustomObject]@{ '_s'='test-stream'; '_l'=$levels[(Get-Random -Maximum $levels.Count)]; '_m'="test-stream message #$($_) - $([guid]::NewGuid())"; Attributes=@{ host=$env:COMPUTERNAME; runId=([guid]::NewGuid()).Guid; index=$_ } } }; Invoke-RestMethod -Uri "$base/v1/logs/batch" -Method Post -ContentType 'application/json' -Body (ConvertTo-Json @{ '_s'='test-stream'; entries=$entries } -Depth 10)
